  }, {
    role: 'user',
    content: 'What are the latest developments (past 7 days) related to this federal opportunity? Include any new solicitation amendments, industry day announcements, competitor activity, or agency budget changes.\n\nOpportunity: ' + $json.title + '\nAgency: ' + ($json.agency || 'Unknown') + '\nNAICS: ' + ($json.naics || 'Unknown')
  }],
  temperature: 0.1,
  max_tokens: 1000,
  return_citations: true,
  search_recency_filter: 'week'
}) }}

parameters.jsCode:
var opp = $('Process Each Opp').first().json;
var perplexity = $input.first().json;
var content = perplexity.choices ? perplexity.choices[0].message.content : 'No results';
var citations = perplexity.citations || [];

return [{ json: {
  opp_id: opp.id,
  title: opp.title,
  agency: opp.agency || 'Unknown',
  pwin: opp.pwin || 0,
  intel: content.substring(0, 2000),
  citation_count: citations.length,
  citations: citations.slice(0, 5),
  researched_at: new Date().toISOString()
} }];
